#!/usr/bin/env node
// Embeds all client static assets and hls.js into src/client-bundle.js as
// base64-encoded buffers so @yao-pkg/pkg bundles them via the src/**/*.js
// scripts glob. The pkg.assets glob mechanism is broken for node20 targets,
// so asset files must live inside a bundled .js file instead.
//
// Run whenever client/ files or node_modules/hls.js change:
//   node scripts/generate-client-bundle.js
//
// The generated file is committed to the repo. scripts/build-exe.js re-runs
// it before packaging to keep the bundle in sync.

'use strict';

const fs   = require('fs');
const path = require('path');

const ROOT        = path.resolve(__dirname, '..');
const CLIENT_DIR  = path.join(ROOT, 'client');
const LANDING_DIR = path.join(ROOT, 'landing');
const HLS_SRC     = path.join(ROOT, 'node_modules', 'hls.js', 'dist', 'hls.min.js');
const MATTER_SRC  = path.join(ROOT, 'node_modules', 'matter-js', 'build', 'matter.min.js');
const OUTPUT      = path.join(ROOT, 'src', 'client-bundle.js');

const MIME = {
  '.html':  'text/html; charset=utf-8',
  '.css':   'text/css; charset=utf-8',
  '.js':    'text/javascript',
  '.woff2': 'font/woff2',
  '.woff':  'font/woff',
  '.ttf':   'font/ttf',
  '.md':    'text/plain',
  '.json':  'application/json',
  '.jpg':   'image/jpeg',
  '.jpeg':  'image/jpeg',
  '.png':   'image/png',
};

function mimeFor(ext) {
  return MIME[ext.toLowerCase()] || 'application/octet-stream';
}

function walk(dir, prefix) {
  const out = [];
  for (const name of fs.readdirSync(dir).sort()) {
    const full    = path.join(dir, name);
    const urlPath = prefix + '/' + name;
    if (fs.statSync(full).isDirectory()) {
      out.push(...walk(full, urlPath));
    } else {
      out.push({ full, urlPath });
    }
  }
  return out;
}

function listClientBundleEntries() {
  if (!fs.existsSync(CLIENT_DIR)) {
    throw new Error('client/ directory not found');
  }
  if (!fs.existsSync(HLS_SRC)) {
    throw new Error('hls.js not installed - run npm install first');
  }
  if (!fs.existsSync(MATTER_SRC)) {
    throw new Error('matter-js not installed - run npm install first');
  }

  const entries = walk(CLIENT_DIR, '');
  // Include landing/ pages so packaged exe can serve /landing/* routes.
  if (fs.existsSync(LANDING_DIR)) {
    entries.push(...walk(LANDING_DIR, '/landing'));
  }
  entries.push({ full: HLS_SRC, urlPath: '/vendor/hls.min.js' });
  entries.push({ full: MATTER_SRC, urlPath: '/vendor/matter.min.js' });
  return entries;
}

function buildClientBundleSource() {
  const entries = listClientBundleEntries();

  const lines = [
    '// AUTO-GENERATED by scripts/generate-client-bundle.js - do not edit by hand.',
    '// Run: node scripts/generate-client-bundle.js',
    '',
    '\'use strict\';',
    '',
    '// Maps URL path -> { data: Buffer, mime: string }',
    'module.exports = {',
  ];

  for (const { full, urlPath } of entries) {
    const ext  = path.extname(full);
    const b64  = fs.readFileSync(full).toString('base64');
    const m    = mimeFor(ext);
    lines.push(`  ${JSON.stringify(urlPath)}: { data: Buffer.from(${JSON.stringify(b64)}, 'base64'), mime: ${JSON.stringify(m)} },`);
  }

  lines.push('};', '');

  return { source: lines.join('\n'), entriesCount: entries.length };
}

function generateClientBundle() {
  const bundle = buildClientBundleSource();
  fs.writeFileSync(OUTPUT, bundle.source, 'utf8');
  return bundle;
}

if (require.main === module) {
  try {
    const bundle = generateClientBundle();
    console.log(`Generated ${OUTPUT} with ${bundle.entriesCount} entries.`);
  } catch (err) {
    console.error(`ERROR: ${err.message}`);
    process.exit(1);
  }
}

module.exports = { buildClientBundleSource, generateClientBundle, listClientBundleEntries, mimeFor, OUTPUT };
